// Reminder: script cadence and closing are controlled in the markdown file.
// This node only prepares text for ElevenLabs.

const episode = $node["Normalize input"].json.episode;
const voiceId = $node["Normalize input"].json.voice_id;
const modelId = $node["Normalize input"].json.model_id;

// Pull binary file from GitHub node safely
const ghItems = $items("GitHub get script file");
const bin = ghItems?.[0]?.binary?.data;

if (!bin || !bin.data) {
  throw new Error("GitHub file binary not found. Ensure GitHub node has 'As Binary Property' ON and output field set to 'data'.");
}

const raw = Buffer.from(bin.data, "base64").toString("utf8");

// Extract script body
const lines = raw.split(/\r?\n/);
const startIndex = lines.findIndex((l) => l.trim().toLowerCase() === "script");
let text = "";

if (startIndex >= 0) {
  text = lines.slice(startIndex + 1).join("\n").trim();
} else {
  text = raw.trim();
}

// ---- Validate locked Awnt Truth closing (Unicode-safe) ----
const REQUIRED_ENDING = ["I'll see you next time.", "We've got this."];

const normalizeLine = (s) =>
  String(s || "")
    .replace(/\u00A0/g, " ")
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .replace(/[’‘]/g, "'")
    .trim();

const normalizedLines = text
  .replace(/\r/g, "")
  .split("\n")
  .map(normalizeLine)
  .filter(Boolean);

if (normalizedLines.length < 2) {
  throw new Error("Script is too short. It must include the locked closing.");
}

const lastTwo = normalizedLines.slice(-2);
const req0 = normalizeLine(REQUIRED_ENDING[0]);
const req1 = normalizeLine(REQUIRED_ENDING[1]);

if (normalizeLine(lastTwo[0]) !== req0 || normalizeLine(lastTwo[1]) !== req1) {
  throw new Error(
    "Script is missing the locked Awnt Truth closing.\n" +
      "The final two lines must be:\n" +
      "I'll see you next time.\n" +
      "We've got this."
  );
}

const safeEpisode = String(episode).padStart(2, "0");
const outPath = `/media/audio/processed/video_${safeEpisode}_ai.mp3`;

return [
  {
    json: {
      episode: safeEpisode,
      voice_id: voiceId,
      model_id: modelId,
      language_code: "en",
      apply_text_normalization: "on",
      voice_settings: {
        stability: 0.38,
        similarity_boost: 0.86,
        style: 0.42,
        use_speaker_boost: true
      },
      text,
      out_path: outPath
    }
  }
];
